class MockImageApiHandler:
    """图片API接口Mock实现"""
    MODULE_NAME = "image_api"
    TASK_STATUS_FLOW = [
        "PENDING", "TEXT_PASSED", "PROMPT_GENERATED",
        "IMAGE_GENERATED", "VI_PASSED", "LOGO_ADDED", "COMPLETED"
    ]

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)
        self._task_store: Dict[str, Dict[str, Any]] = {}

    def generate_image(self, request: Dict[str, Any]) -> Dict[str, Any]:
        """
        生图请求接口Mock实现 对应POST /api/v1/images/generate
        :param request: 生图请求参数 符合GenImageRequest结构
        :return: 任务返回结果
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock API服务异常")

        fixed_value = self._mock_config.get("fixed_generate_value")
        if fixed_value is not None:
            return fixed_value

        task_id = f"task_{random.randint(1000000, 9999999)}"
        task_state = {
            "task_id": task_id,
            "status": "PENDING",
            "original_input": request.get("prompt", ""),
            "enhanced_prompt": None,
            "raw_image_url": None,
            "final_image_url": None,
            "errors": None
        }
        self._task_store[task_id] = task_state
        return {"task_id": task_id, "status": "PENDING"}

    async def get_task_stream(self, task_id: str) -> AsyncGenerator[Dict[str, Any], None]:
        """
        任务状态流接口Mock实现 对应GET /api/v1/tasks/{task_id}/stream
        :param task_id: 任务ID
        :return: SSE流数据
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock任务流服务异常")

        if task_id not in self._task_store:
            yield {
                "event": "error",
                "data": json.dumps({"code": "TASK_NOT_FOUND", "message": "任务不存在"})
            }
            return

        task = self._task_store[task_id]
        flow = self.TASK_STATUS_FLOW.copy()
        if self._mock_config.get("task_failed", False):
            failed_step = random.randint(1, len(flow)-1)
            flow = flow[:failed_step] + ["FAILED"]

        stream_interval = self._mock_config.get("stream_interval", 0.5)
        for idx, status in enumerate(flow):
            task["status"] = status
            progress = int((idx + 1) / len(flow) * 100)

            if status == "PROMPT_GENERATED":
                task["enhanced_prompt"] = f"优化提示词：{task['original_input']}，高清8K，无水印，符合品牌规范"
            elif status == "IMAGE_GENERATED":
                img_id = random.randint(100000, 999999)
                task["raw_image_url"] = f"https://mock-minio.example.com/gen_image/raw/{img_id}.png"
            elif status == "LOGO_ADDED":
                task["final_image_url"] = task["raw_image_url"].replace("/raw/", "/processed/").replace(".png", "_logo.png") if task["raw_image_url"] else None
            elif status == "FAILED":
                task["errors"] = [{"code": "TASK_FAILED", "message": "任务执行失败", "details": "未知系统异常"}]

            yield {
                "event": "status",
                "data": json.dumps({"task": task, "progress": progress}, ensure_ascii=False)
            }
            await asyncio.sleep(stream_interval)


